#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int largestSubarray(vector<int>& nums) {
        unordered_map<int, int> prefix_sum;
        int curr_sum = 0;
        int max_len = 0;
        for (int i = 0; i < nums.size(); i++) {
            curr_sum += nums[i];
            if (curr_sum == 0) {
                max_len = max(max_len, i + 1);
            }
            if (prefix_sum.find(curr_sum) != prefix_sum.end()) {
                max_len = max(max_len, i - prefix_sum[curr_sum]);
            } else {
                prefix_sum[curr_sum] = i;
            }
        }
        return max_len;
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    int ans = sol.largestSubarray(nums);
    cout << ans << '\n';
    return 0;
}
